:"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"id"},{"@type":"WebPage","@id":"https://roadtostudy.com/id/cara-mengembangkan-kosakata-aktif-dan-pasif-dalam-bahasa-turki/#webpage","url":"https://roadtostudy.com/id/cara-mengembangkan-kosakata-aktif-dan-pasif-dalam-bahasa-turki/","name":"Cara Mengembangkan Kosakata Aktif dan Pasif dalam Bahasa Turki - RoadtoStudy","datePublished":"2026-04-16T06:00:00+03:00","dateModified":"2026-04-16T06:00:00+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"id"},{"@type":"Person","@id":"https://roadtostudy.com/id/author/murat/","name":"Murat","url":"https://roadtostudy.com/id/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"id"}},{"@type":"BlogPosting","headline":"Cara Mengembangkan Kosakata Aktif dan Pasif dalam Bahasa Turki - RoadtoStudy","datePublished":"2026-04-16T06:00:00+03:00","dateModified":"2026-04-16T06:00:00+03:00","articleSection":"Pembelajaran Bahasa","author":{"@id":"https://roadtostudy.com/id/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Tingkatkan kosakata aktif dan pasif Anda dalam belajar Bahasa Turki. Temukan metode efektif untuk mencapai tujuan Anda!","name":"Cara Mengembangkan Kosakata Aktif dan Pasif dalam Bahasa Turki - RoadtoStudy","@id":"https://roadtostudy.com/id/cara-mengembangkan-kosakata-aktif-dan-pasif-dalam-bahasa-turki/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/id/cara-mengembangkan-kosakata-aktif-dan-pasif-dalam-bahasa-turki/#webpage"},"in